export class Decimal{static fromUserInput(t,i){Decimal.verifyFractionalDigits(i);const r=t.match(/[^0-9.]/);if(r)throw new Error(`Invalid character at position ${r.index+1}`);let a,e;if(""===t)a="0",e="";else if(-1===t.search(/\./))a=t,e="";else{const i=t.split(".");switch(i.length){case 0:case 1:throw new Error("Fewer than two elements in split result. This must not happen here.");case 2:if(!i[1])throw new Error("Fractional part missing");a=i[0],e=i[1].replace(/0+$/,"");break;default:throw new Error("More than one separator found")}}if(e.length>i)throw new Error("Got more fractional digits than supported");const n=`${a}${e.padEnd(i,"0")}`;return new Decimal(n,i)}static fromAtomics(t,i){return Decimal.verifyFractionalDigits(i),new Decimal(t,i)}static verifyFractionalDigits(t){if(!Number.isInteger(t))throw new Error("Fractional digits is not an integer");if(t<0)throw new Error("Fractional digits must not be negative");if(t>30)throw new Error("Fractional digits must not exceed 30")}get atomics(){return this.data.atomics.toString()}get fractionalDigits(){return this.data.fractionalDigits}data;constructor(t,i){if(!t.match(/^[0-9]+$/))throw new Error("Invalid string format. Only non-negative integers in decimal representation supported.");this.data={atomics:BigInt(t),fractionalDigits:i}}toString(){const t=BigInt(10)**BigInt(this.data.fractionalDigits),i=this.data.atomics/t,r=this.data.atomics%t;if(0n===r)return i.toString();{const t=r.toString().padStart(this.data.fractionalDigits,"0").replace(/0+$/,"");return`${i.toString()}.${t}`}}}